import '../lib/packet_decoder.dart';
import '../lib/temperature.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final frame = decodeSensorFrame([0xc4, 0x09, 0x01]);
  check(frame.rawTemperature == 2500, 'positive raw temperature');
  check(temperatureCelsius(frame) == 25.0, 'positive Celsius conversion');

  var malformedRejected = false;
  try {
    decodeSensorFrame([0, 1]);
  } on FormatException {
    malformedRejected = true;
  }
  check(malformedRejected, 'malformed packet length is rejected');
}
